// Helper to get material price by region
export function getMaterialPrice(itemCode, region = 'national') {
  for (const cat of Object.values(MATERIAL_CATEGORIES)) {
    const found = cat.items.find(i => i.code === itemCode);
    if (found) {
      return { ...found, price: found[region] || found.national };
    }
  }
  return null;
}

// Helper to search materials
export function searchMaterials(query, region = 'national') {
  const q = query.toLowerCase();
  const results = [];
  for (const [catKey, cat] of Object.entries(MATERIAL_CATEGORIES)) {
    for (const item of cat.items) {
      if (item.description.toLowerCase().includes(q) || item.code.toLowerCase().includes(q)) {
        results.push({ ...item, category: cat.name, categoryKey: catKey, price: item[region] || item.national });
      }
    }
  }
  return results;
}

// Formula builder for tender pricing
export function buildTenderPriceRate(directCost, pAndG = 15, overhead = 10, profit = 8, contingency = 5) {
  const pAndGAmount = directCost * (pAndG / 100);
  const overheadAmount = (directCost + pAndGAmount) * (overhead / 100);
  const profitAmount = (directCost + pAndGAmount + overheadAmount) * (profit / 100);
  const contingencyAmount = directCost * (contingency / 100);
  return {
    directCost,
    pAndG: { percentage: pAndG, amount: pAndGAmount },
    overheads: { percentage: overhead, amount: overheadAmount },
    profit: { percentage: profit, amount: profitAmount },
    contingency: { percentage: contingency, amount: contingencyAmount },
    totalRate: directCost + pAndGAmount + overheadAmount + profitAmount + contingencyAmount
  };
}

export default MATERIAL_CATEGORIES;
